import rclpy
from rclpy.node import Node
from sensor_msgs.msg import Imu
from nav_msgs.msg import Odometry
from geometry_msgs.msg import Twist, Quaternion, TransformStamped
import serial
import struct
import threading
import time
import numpy as np
from tf2_ros import TransformBroadcaster
from collections import deque
import crcmod

class UnifiedCarController(Node):
    def __init__(self):
        super().__init__('unified_car_controller')

        # ==================== 原有配置（完全保留） ====================
        # 发布器：新增IMU发布器，其余保留
        self.imu_pub = self.create_publisher(Imu, '/imu/data', 10)  # 仅新增这行
        self.odom_pub = self.create_publisher(Odometry, '/odom', 10)
        self.tf_broadcaster = TransformBroadcaster(self)

        self.cmd_vel_sub = self.create_subscription(
            Twist,
            '/cmd_vel',
            self.cmd_vel_callback,
            10
        )

        # 串口配置（完全保留你的原有配置）
        self.serial_port = '/dev/ttyAMA0'
        self.baudrate = 115200
        self.ser = None
        self.serial_lock = threading.Lock()

        # 协议定义：新增IMU消息ID，其余保留
        self.FRAME_HEAD = bytes([0xAA, 0x55])
        self.FRAME_TAIL = bytes([0x0D, 0x0A])
        self.MSG_ID_ENCODER = 0x11          # 原有编码器ID
        self.MSG_ID_IMU = 0x12              # 新增IMU ID（对齐c30d-car）
        self.MSG_ID_VELOCITY_CMD = 0x01

        # 帧长度（根据c30d-car协议调整，保持原有编码器长度，新增IMU长度）
        self.ENCODER_PAYLOAD_LEN = 27
        self.IMU_PAYLOAD_LEN = 34           # c30d-car标准IMU载荷长度
        self.VEL_CMD_PAYLOAD_LEN = 6

        # 缓冲区（保留原有）
        self.recv_buffer = bytearray()
        self.send_buffer = deque()
        self.buffer_lock = threading.Lock()

        # 状态变量：新增IMU相关，其余保留
        self.last_encoder_time = None
        self.last_imu_time = None           # 新增IMU超时标记
        self.encoder_counts = [0, 0, 0, 0]
        self.encoder_seq = 0
        # 新增IMU状态（仅新增这部分）
        self.imu_data = {
            'gyro': [0.0, 0.0, 0.0],
            'accel': [0.0, 0.0, 0.0],
            'euler': [0.0, 0.0, 0.0],
            'temperature': 0.0,
            'seq': 0
        }
        self.position = np.array([0.0, 0.0, 0.0])
        self.velocity = np.array([0.0, 0.0, 0.0])

        # CRC（保留原有）
        self.crc16_func = crcmod.predefined.mkCrcFun('crc-ccitt-false')

        # 初始化（完全保留）
        self.init_serial()
        self.running = True
        self.recv_thread = threading.Thread(target=self.receive_loop, daemon=True)
        self.send_thread = threading.Thread(target=self.send_loop, daemon=True)
        self.process_thread = threading.Thread(target=self.process_loop, daemon=True)
        self.recv_thread.start()
        self.send_thread.start()
        self.process_thread.start()

        self.get_logger().info('Car控制器启动（已适配IMU+编码器）')

    # ==================== 原有串口初始化（完全保留，仅注释ioctl相关） ====================
    def init_serial(self):
        try:
            with self.serial_lock:
                self.ser = serial.Serial(
                    port=self.serial_port,
                    baudrate=self.baudrate,
                    bytesize=serial.EIGHTBITS,
                    parity=serial.PARITY_NONE,
                    stopbits=serial.STOPBITS_ONE,
                    timeout=0.01,
                    write_timeout=0.1,
                    rtscts=False,  # 仅新增这两行避免ioctl错误
                    dsrdtr=False
                )
                self.get_logger().info(f'串口 {self.serial_port} 打开成功')
        except Exception as e:
            self.get_logger().error(f'串口打开失败: {e}')
            self.ser = None

    # ==================== 原有接收/发送线程（完全保留，仅加详细错误日志） ====================
    def receive_loop(self):
        while self.running:
            try:
                with self.serial_lock:
                    if not self.ser or not self.ser.is_open:
                        time.sleep(0.1)
                        continue
                    if self.ser.in_waiting > 0:
                        data = self.ser.read(self.ser.in_waiting)
                        with self.buffer_lock:
                            self.recv_buffer.extend(data)
                        self.parse_received_data()
            except serial.SerialException as e:
                self.get_logger().error(f'串口接收异常: {type(e).__name__} - {e}')
                time.sleep(0.1)
                self.init_serial()
            except Exception as e:
                self.get_logger().error(f'接收线程错误: {e}')
                time.sleep(0.01)

    def send_loop(self):
        # 完全保留你的原有发送逻辑（对齐c30d-car）
        while self.running:
            try:
                with self.serial_lock:
                    if self.ser and self.ser.is_open and self.send_buffer:
                        with self.buffer_lock:
                            data = self.send_buffer.popleft()
                        self.ser.write(data)
                        self.ser.flush()
                time.sleep(0.001)
            except Exception as e:
                self.get_logger().error(f'发送线程错误: {e}')
                time.sleep(0.01)

    # ==================== 数据解析（仅新增IMU分支，其余保留） ====================
    def parse_received_data(self):
        with self.buffer_lock:
            while len(self.recv_buffer) >= 6:
                try:
                    head_idx = self.recv_buffer.find(self.FRAME_HEAD)
                    if head_idx < 0:
                        self.recv_buffer.clear()
                        break
                    if head_idx > 0:
                        self.recv_buffer = self.recv_buffer[head_idx:]

                    if len(self.recv_buffer) < 4:
                        break
                    payload_len = self.recv_buffer[2]
                    frame_len = 2 + 1 + 1 + payload_len + 2 + 2
                    if len(self.recv_buffer) < frame_len:
                        break

                    frame = bytes(self.recv_buffer[:frame_len])
                    if frame[-2:] != self.FRAME_TAIL:
                        self.recv_buffer.pop(0)
                        continue

                    # 仅新增IMU帧处理分支，编码器分支保留
                    self.process_frame(frame)
                    self.recv_buffer = self.recv_buffer[frame_len:]

                except Exception as e:
                    self.get_logger().error(f'解析数据错误: {e}')
                    if len(self.recv_buffer) > 0:
                        self.recv_buffer.pop(0)

    def process_frame(self, frame):
        """仅新增IMU帧分发，其余保留"""
        try:
            msg_id = frame[3]
            payload_len = frame[2]

            if msg_id == self.MSG_ID_ENCODER and payload_len == self.ENCODER_PAYLOAD_LEN:
                self.process_encoder_frame(frame)  # 原有编码器逻辑
            elif msg_id == self.MSG_ID_IMU and payload_len == self.IMU_PAYLOAD_LEN:
                self.process_imu_frame(frame)     # 新增IMU处理
            else:
                self.get_logger().warn(f'未知帧: ID=0x{msg_id:02X}')
        except Exception as e:
            self.get_logger().error(f'处理帧错误: {e}')

    def process_encoder_frame(self, frame):
        """完全保留你的原有编码器解析逻辑"""
        try:
            seq, = struct.unpack('<H', frame[4:6])
            timestamp_ms, = struct.unpack('<I', frame[6:10])
            dt_us, = struct.unpack('<I', frame[10:14])
            dcount_a, = struct.unpack('<i', frame[14:18])
            dcount_b, = struct.unpack('<i', frame[18:22])
            dcount_c, = struct.unpack('<i', frame[22:26])
            dcount_d, = struct.unpack('<i', frame[26:30])

            crc_received, = struct.unpack('<H', frame[30:32])
            crc_calculated = self.crc16_func(frame[2:30])
            if crc_received != crc_calculated:
                self.get_logger().warn('编码器CRC错误')
                return

            self.encoder_counts = [dcount_a, dcount_b, dcount_c, dcount_d]
            self.encoder_seq = seq
            self.last_encoder_time = time.time()

        except Exception as e:
            self.get_logger().error(f'解析编码器帧错误: {e}')

    def process_imu_frame(self, frame):
        """仅新增：IMU解析逻辑（对齐c30d-car协议）"""
        try:
            # 1. 解析基础字段（c30d-car标准格式）
            seq, = struct.unpack('<H', frame[4:6])
            timestamp_ms, = struct.unpack('<I', frame[6:10])

            # 2. 陀螺仪（±2000°/s → rad/s）
            gyro_x_raw, = struct.unpack('<h', frame[10:12])
            gyro_y_raw, = struct.unpack('<h', frame[12:14])
            gyro_z_raw, = struct.unpack('<h', frame[14:16])
            gyro_scale = 2000.0 / 32768.0 * (np.pi / 180.0)
            gyro_x = gyro_x_raw * gyro_scale
            gyro_y = gyro_y_raw * gyro_scale
            gyro_z = gyro_z_raw * gyro_scale

            # 3. 加速度计（±8g → m/s²）
            accel_x_raw, = struct.unpack('<h', frame[16:18])
            accel_y_raw, = struct.unpack('<h', frame[18:20])
            accel_z_raw, = struct.unpack('<h', frame[20:22])
            accel_scale = 8.0 * 9.80665 / 32768.0
            accel_x = accel_x_raw * accel_scale
            accel_y = accel_y_raw * accel_scale
            accel_z = accel_z_raw * accel_scale

            # 4. 温度 + 欧拉角
            temp_raw, = struct.unpack('<h', frame[22:24])
            roll, = struct.unpack('<f', frame[24:28])
            pitch, = struct.unpack('<f', frame[28:32])
            yaw, = struct.unpack('<f', frame[32:36])

            # 5. CRC校验
            crc_received, = struct.unpack('<H', frame[36:38])
            crc_calculated = self.crc16_func(frame[2:36])
            if crc_received != crc_calculated:
                self.get_logger().warn('IMU CRC错误')
                return

            # 6. 更新IMU状态
            self.imu_data.update({
                'gyro': [gyro_x, gyro_y, gyro_z],
                'accel': [accel_x, accel_y, accel_z],
                'euler': [roll, pitch, yaw],
                'temperature': temp_raw / 100.0,
                'seq': seq
            })
            self.last_imu_time = time.time()

            # 7. 发布IMU数据
            self.publish_imu_data(timestamp_ms)

        except Exception as e:
            self.get_logger().error(f'解析IMU帧错误: {e}')

    # ==================== 新增：IMU发布逻辑（仅新增） ====================
    def publish_imu_data(self, timestamp_ms):
        """发布c30d-car标准IMU消息"""
        imu_msg = Imu()
        imu_msg.header.stamp = self.get_clock().now().to_msg()
        imu_msg.header.frame_id = 'imu_link'
        imu_msg.header.seq = self.imu_data['seq']

        # 角速度
        imu_msg.angular_velocity.x = self.imu_data['gyro'][0]
        imu_msg.angular_velocity.y = self.imu_data['gyro'][1]
        imu_msg.angular_velocity.z = self.imu_data['gyro'][2]

        # 线加速度
        imu_msg.linear_acceleration.x = self.imu_data['accel'][0]
        imu_msg.linear_acceleration.y = self.imu_data['accel'][1]
        imu_msg.linear_acceleration.z = self.imu_data['accel'][2]

        # 欧拉角转四元数
        roll, pitch, yaw = self.imu_data['euler']
        cy = np.cos(yaw * 0.5)
        sy = np.sin(yaw * 0.5)
        cp = np.cos(pitch * 0.5)
        sp = np.sin(pitch * 0.5)
        cr = np.cos(roll * 0.5)
        sr = np.sin(roll * 0.5)
        imu_msg.orientation.w = cr * cp * cy + sr * sp * sy
        imu_msg.orientation.x = sr * cp * cy - cr * sp * sy
        imu_msg.orientation.y = cr * sp * cy + sr * cp * sy
        imu_msg.orientation.z = cr * cp * sy - sr * sp * cy

        self.imu_pub.publish(imu_msg)

    # ==================== 原有速度命令/发送逻辑（完全保留） ====================
    def cmd_vel_callback(self, msg):
        """完全保留你的原有发送逻辑（对齐c30d-car）"""
        try:
            vx = msg.linear.x
            vy = msg.linear.y
            omega = msg.angular.z
            vx_mm_s = int(vx * 1000.0)
            vy_mm_s = int(vy * 1000.0)
            wz_mrad_s = int(omega * 1000.0)
            control_frame = self.build_velocity_frame(vx_mm_s, vy_mm_s, wz_mrad_s)
            with self.buffer_lock:
                self.send_buffer.append(control_frame)
        except Exception as e:
            self.get_logger().error(f'处理速度命令错误: {e}')

    def build_velocity_frame(self, vx_mm_s, vy_mm_s, wz_mrad_s):
        """完全保留你的原有帧构建逻辑"""
        frame = bytearray()
        frame.extend(self.FRAME_HEAD)
        frame.append(self.VEL_CMD_PAYLOAD_LEN)
        frame.append(self.MSG_ID_VELOCITY_CMD)
        frame.extend(struct.pack('<h', vx_mm_s))
        frame.extend(struct.pack('<h', vy_mm_s))
        frame.extend(struct.pack('<h', wz_mrad_s))
        checksum = 0
        for b in frame[2:8]:
            checksum ^= b
        frame.append(checksum)
        frame.extend(self.FRAME_TAIL)
        return bytes(frame)

    # ==================== 处理线程（仅新增IMU超时检测） ====================
    def process_loop(self):
        """仅新增IMU超时，其余保留"""
        while self.running:
            try:
                current_time = time.time()
                # 原有编码器超时
                if self.last_encoder_time and (current_time - self.last_encoder_time > 0.5):
                    self.get_logger().warn('编码器数据超时')
                    self.last_encoder_time = None
                # 新增IMU超时
                if self.last_imu_time and (current_time - self.last_imu_time > 0.5):
                    self.get_logger().warn('IMU数据超时')
                    self.last_imu_time = None
                time.sleep(0.1)
            except Exception as e:
                self.get_logger().error(f'处理线程错误: {e}')
                time.sleep(0.1)

    # ==================== 原有清理逻辑（完全保留） ====================
    def destroy_node(self):
        self.get_logger().info('关闭控制器...')
        self.running = False
        with self.serial_lock:
            if self.ser and self.ser.is_open:
                self.ser.close()
        super().destroy_node()

def main(args=None):
    rclpy.init(args=args)
    executor = rclpy.executors.MultiThreadedExecutor()
    node = UnifiedCarController()
    executor.add_node(node)
    try:
        executor.spin()
    except KeyboardInterrupt:
        node.get_logger().info('退出控制器')
    finally:
        node.destroy_node()
        rclpy.shutdown()

if __name__ == '__main__':
    main()